import{_ as e,o as a,c as t,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"绝响之物","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/2.社交类/绝响之物/绝响之物.md","filePath":"4.资源分区/2.改造与功法/改造/2.社交类/绝响之物/绝响之物.md"}'),s={name:"4.资源分区/2.改造与功法/改造/2.社交类/绝响之物/绝响之物.md"};function o(d,p,l,_,i,c){return a(),t("div",null,[...p[0]||(p[0]=[r("h1",{id:"绝响之物",tabindex:"-1"},[b("绝响之物 "),r("a",{class:"header-anchor",href:"#绝响之物","aria-label":'Permalink to "绝响之物"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风029特别节愚人版")])])],-1),n('<h1 id="绝响之物-1" tabindex="-1">绝响之物 <a class="header-anchor" href="#绝响之物-1" aria-label="Permalink to &quot;绝响之物&quot;">​</a></h1><p>绝响之物</p><p>D级：D+600<br> 在此阶段下，你立即获得傀儡谣、能剧</p><p>承载命运的，只不过是傀儡。<br> 生存是诱因，灭亡是结果，绝响之物，正在等待…</p><p>傀儡谣：<br> 梦如春水已流逝，唯余怨恨几飘零。<br> 绝响之物改造会将你的生命值改为结构值，从获得绝响之物改造起，你的头部装备位将只能装备面具类的物品，并获得等同于绝响之物最高支线等级*2的【浮世】装备槽。<br> 在未激活【怨恨凋零】时，你的四肢将会由傀儡丝操控，这是一个画风表现。激活【怨恨凋零】是一个移动动作，控制着你的傀儡丝将会全部崩断，激活【怨恨凋零】后，这个状态将会持续一个场景。</p><p>能剧：<br> 在获得绝响之物改造时，你需要从下列能面中选择一张获得，选择后不能更换。<br> 能面将会占据你的头部装备位，最开始，能面上将不存在任何绘制的纹路，并根据经过的影片，纹路将会逐渐显现，当纹路达到4道时，能面将停止出现更多花纹。<br> 你最多可以为这个能力再额外支付10XP，并再选择一张能面获得之，花纹需要重新积累，更换能面是一个花招动作。</p><p>●白鵺<br> 1道花纹：你在决心属性的相关检定中将获得你的传奇决心*1点检定上的修行加值。</p><p>2道花纹：每轮一次，你进行过表达检定的那一轮进行移动时，可以再进行一次风度+表达检定，在那次移动中，你的最大移动距离将增加这次检定的结果/米。</p><p>3道花纹：现在，每轮一次，你可以使用一个反射动作在回合外进行移动，其移动距离等同于2道花纹给予的额外移动距离效果，每次移动时需要重新进行检定，这个能力不具有打断性。</p><p>4道花纹：现在，基于3道花纹给予的效果，这一能力将具有打断性。</p><p>●鸫鸟<br> 1道花纹：你在耐力属性的相关检定中将获得你的传奇耐力*1点检定上的修行加值。</p><p>2道花纹：现在，你获得基于某你使用的武器的【谐振】，该武器由你指定，你最多只能同时保持一件武器的【谐振】，你因此获得的【谐振】将改为提供等量的耐力属性相关检定的器械加值。</p><p>3道花纹：你在强韧检定中将获得你的传奇耐力*2点检定上的修行加值。</p><p>4道花纹：只要你的意志池不空，你就始终视为具有对你攻击而言的【劣化1】。</p><p>●百花<br> 1道花纹：你每有一种类型的本源碎片，就可以选择一种你有的通用能量池提升3点上限，你最多能以此法提升三次。</p><p>2道花纹：当你使用【携手共进】时，你再同时额外获得1点快速维修（医疗点8）。</p><p>3道花纹：当你触发【幕后玩家】时，将获得的全检定加值改为2点，将进行急救检定获得的额外附加成功改为2点。</p><p>4道花纹：若你拥有【夜莺之舞】，则将持续生效直至你不再拥有任何临时生命为止，你始终视为具有基于闪避防御的【坚韧】。</p><p>C级：C+1200<br> 在此阶段下，你获得傀儡谣+、敕罪</p><p>傀儡谣+：<br> 现在，傀儡谣+会在原特性的基础上再为你提供：当你激活【怨恨凋零】时，你每拥有2个D级【浮世】装备就获得1点偏斜防御。C/B/A/S级【浮世】装备将被视为2/4/8/16个D级【浮世】装备。</p><p>敕罪：<br> 处于战斗轮中时，每一轮结束时，若你在本轮中至少使用了2点意志力，则获得1层【罪】。你可以在满足条件时立即使用数点【罪】以获得对应效果，战斗轮结束时，立即失去所有【罪】。<br> 1.若你的某次攻击出目低于总DP的三分之一，则你可以消耗2层【罪】，重掷本次攻击，但必须接受第二次重掷的结果。<br> 2.当你在本场战斗轮中首次进行开启基因锁尝试时，你可以消耗等同于你此次基因锁等级*1层【罪】，为此次尝试提供2*消耗的【罪】层数点基因锁加值。<br> 3.当你试图更换能面时，你可以消耗1层【罪】，本次更换能面不需要消耗AP。<br> 4.当你触发本源主流效果时，你可以消耗X层【罪】，选择一项你未拥有的该系支流，获得其直至该回合结束。当其所需本源点为3时，X=1，所需为6时，X=2。</p><p>B级：B+2400<br> 在此阶段下，你获得傀儡谣++、世流</p><p>傀儡谣++：<br> 当你激活【怨恨凋零】后，每轮一次，你可以选择一项你具有的【浮世】装备，无需使用动作将其激活。激活【怨恨凋零】时，也可以选择那轮不生效傀儡谣++，而是获得4点仅能用于激活【怨恨凋零】的AP。</p><p>世流：<br> 每个战斗场景的第9轮开始时，【世流】将开始生效直至那一轮结束。<br> 在本场战斗中，每当你满足一种下列条件时，【世流】的生效时间将提前一轮，每种条件最多生效一次。最多提前至本场战斗的第2轮生效。<br> 1.累计使用了2层【罪】及以上。<br> 2.激活【怨恨凋零】。<br> 3.更换能面。<br> 4.激活超过2件【浮世】装备。<br> 5.尝试过开启基因锁。<br> 6.杀死敌对目标。<br> 7.触发本源支流。<br> 8.使用应对技。<br> 9.造成异常点数。<br> 【世流】生效的那一轮中，你将立即获得【威仪】，并使你本轮的第一次攻击检定出目增加一半。</p><p>A级：在此阶段下，你立即获得长恨、绝响</p><p>长恨：<br> 当你受到致死伤害时，你可以选择立即使你具有的X件D级【浮世】装备彻底损毁，并抵御这次伤害中的Y点伤害（Y=6X+X/2），当损毁的【浮世】装备为C级或更高时，C/B/A/S级【浮世】装备将被视为2/4/8/16个D级【浮世】装备。彻底损毁的【浮世】装备将失去所有效果，直至回到主神空间为止。</p><p>绝响：<br> 你的结构值现在变为1.5倍生命值，而非1倍。你可以以一个自由动作开启，以你为中心，260米范围内的所有敌对目标将始终受到B级命运来源的沉默状态影响，若某角色因此而被沉默，则还会陷入D级命运来源的困难地形效果，免疫困难地形则可以免疫这个效果。你可以通过消耗1/3/6/12层【罪】将这一效果的等级提升至C/B/A/S级。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',29)])])}const D=e(s,[["render",o]]);export{f as __pageData,D as default};
